+        return 0;
+    }
+
+    let Ok(agent_entries) = std::fs::read_dir(&agents_dir) else {
+        return 0;
+    };
+
+    agent_entries
+        .flatten()
+        .filter_map(|entry| {
+            let Ok(file_type) = entry.file_type() else {
+                return None;
+            };
+            if !file_type.is_dir() || file_type.is_symlink() {
+                return None;
+            }
+            is_real_file(&entry.path().join("profile.json")).then_some(())
+        })
+        .count()
